"use client";

import {
  Button,
  Card,
  Dropdown,
  Field,
  Input,
  Option,
  Spinner,
  Text,
  makeStyles,
  tokens,
} from "@fluentui/react-components";
import { Suspense, useEffect, useMemo, useState } from "react";
import { useRouter, useSearchParams } from "next/navigation";

type ProjectOption = {
  id: string;
  title: string;
  customer?: { id: string; name: string } | null;
};

const useStyles = makeStyles({
  layout: { display: "flex", flexDirection: "column", gap: "16px" },
  card: { padding: "16px", borderRadius: "var(--app-radius)" },
  subtitle: { color: tokens.colorNeutralForeground3, whiteSpace: "pre-line" },
});

export default function B2BImportsPage() {
  return (
    <Suspense fallback={<Spinner label="Loading…" />}>
      <B2BImportsPageInner />
    </Suspense>
  );
}

function B2BImportsPageInner() {
  const styles = useStyles();
  const router = useRouter();
  const searchParams = useSearchParams();

  const preProjectId = searchParams.get("projectId") ?? "";

  const [projects, setProjects] = useState<ProjectOption[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const [projectId, setProjectId] = useState(preProjectId);
  const [productUrl, setProductUrl] = useState("");
  const [importingProduct, setImportingProduct] = useState(false);

  const load = useMemo(
    () => async () => {
      setLoading(true);
      setError(null);
      try {
        const res = await fetch("/api/b2b/projects");
        const payload = await res.json();
        if (!res.ok) throw new Error(payload?.error || "Unable to load projects.");
        setProjects((payload?.items ?? []) as ProjectOption[]);
      } catch (err) {
        setError(err instanceof Error ? err.message : "Unable to load projects.");
      } finally {
        setLoading(false);
      }
    },
    []
  );

  useEffect(() => {
    load();
  }, [load]);

  useEffect(() => {
    if (!preProjectId) return;
    setProjectId(preProjectId);
  }, [preProjectId]);

  const selectedProject = projects.find((p) => p.id === projectId) ?? null;

  const import1688Product = async () => {
    const url = productUrl.trim();
    if (!projectId || !url) return;
    setImportingProduct(true);
    setError(null);
    try {
      const res = await fetch("/api/b2b/import/1688-product", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ project_id: projectId, url }),
      });
      const payload = await res.json();
      if (!res.ok) throw new Error(payload?.error || "Import failed.");
      if (payload?.id) router.push(`/app/b2b/candidates/${payload.id}`);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Import failed.");
    } finally {
      setImportingProduct(false);
    }
  };

  return (
    <div className={styles.layout}>
      <Card className={styles.card}>
        <Text weight="semibold">Imports</Text>
        <Text size={200} className={styles.subtitle}>
          Single-product import flow for 1688.
          {"\n"}Uses the same product-page scraper path as Production Queue/DigiDeal.
          {"\n"}Images are captured from both:
          {"\n"}1) Main gallery
          {"\n"}2) Description body (long detail images)
        </Text>
        {error ? (
          <Text style={{ color: tokens.colorStatusDangerForeground1 }}>{error}</Text>
        ) : null}
        {loading ? <Spinner label="Loading…" /> : null}
      </Card>

      <Card className={styles.card}>
        <Text weight="semibold">Import 1688 product URL</Text>
        <Text size={200} className={styles.subtitle}>
          Creates a product candidate with raw scrape JSON + normalized fields.
        </Text>

        <Field label="Project" required>
          <Dropdown
            selectedOptions={projectId ? [projectId] : []}
            value={selectedProject ? selectedProject.title : ""}
            placeholder="Select a project"
            onOptionSelect={(_, data) => setProjectId(String(data.optionValue || ""))}
          >
            {projects.map((p) => (
              <Option key={p.id} value={p.id} text={p.title}>
                {p.title}
              </Option>
            ))}
          </Dropdown>
        </Field>

        <Field label="1688 product URL" required>
          <Input
            value={productUrl}
            onChange={(_, data) => setProductUrl(data.value)}
            placeholder="https://detail.1688.com/offer/..."
          />
        </Field>

        <Button
          appearance="primary"
          disabled={importingProduct || !projectId || !productUrl.trim()}
          onClick={import1688Product}
        >
          {importingProduct ? "Importing…" : "Import"}
        </Button>
      </Card>
    </div>
  );
}
